import {Pass, FullScreenQuad} from "three/examples/jsm/postprocessing/Pass.js";
import {
    CanvasTexture,
    GLSL3,
    LinearFilter,
    NearestFilter,
    RGBAFormat,
    ShaderMaterial,
    UnsignedByteType,
    Vector2,
    Vector4,
    WebGLRenderTarget
} from "three";

import asciiVertexShader from "./shaders/asciiVertex.glsl";
import asciiSamplingShader from "./shaders/asciiSampling.glsl";
import asciiRenderShader from "./shaders/asciiRender.glsl";

/**
 * GPU ASCII renderer using 6D shape-vector character matching.
 *
 * Two-step pipeline:
 *   Step 1 (low-res): Sample scene texture, match to nearest character vector
 *   Step 2 (full-res): Render glyphs from font atlas with split view support
 *
 * Based on Alex Harri's ASCII rendering algorithm.
 */
export class AsciiPass extends Pass {

    constructor(options = {}) {
        super();
        this.needsSwap = true;

        // Configuration
        this.cellSize = options.cellSize || 12;
        this.crunchExponent = options.crunchExponent || 1.5;
        this.splitPosition = options.splitPosition || 1.0;
        this.fontFamily = options.fontFamily || "monospace";

        // Sampling circle positions from default.json metadata (normalized [0,1] within cell)
        this._samplePoints = [
            new Vector2(0.3, 0.23), new Vector2(0.7, 0.18),
            new Vector2(0.3, 0.50), new Vector2(0.7, 0.50),
            new Vector2(0.3, 0.82), new Vector2(0.7, 0.77)
        ];

        // Circle radius for mipmap level calculation
        this._circleRadius = 0.28125;

        // Parse and normalize character vectors
        const alphabetData = options.alphabetData;
        const {charVecA, charVecB, characters} = this._prepareCharacterVectors(alphabetData);

        // Store characters for atlas regeneration
        this._characters = characters;

        // Generate runtime font atlas
        this._atlasGrid = new Vector2(10, 8); // 10 cols x 8 rows for 80 chars
        this._atlasTexture = this._generateFontAtlas(characters, this.cellSize);

        // Low-res sampling render target (one pixel per grid cell)
        this._samplingTarget = new WebGLRenderTarget(1, 1, {
            minFilter: NearestFilter,
            magFilter: NearestFilter,
            format: RGBAFormat,
            type: UnsignedByteType,
            generateMipmaps: false,
            depthBuffer: false,
            stencilBuffer: false
        });

        // Step 1: Sampling + matching shader
        this._samplingMaterial = new ShaderMaterial({
            glslVersion: GLSL3,
            uniforms: {
                tDiffuse: {value: null},
                uSamplePoints: {value: this._samplePoints},
                uCellSize: {value: new Vector2(this.cellSize, this.cellSize)},
                uSceneResolution: {value: new Vector2(1, 1)},
                uCrunchExponent: {value: this.crunchExponent},
                uCircleRadius: {value: this._circleRadius},
                uCharVecA: {value: charVecA},
                uCharVecB: {value: charVecB}
            },
            vertexShader: asciiVertexShader,
            fragmentShader: asciiSamplingShader
        });

        // Step 2: Glyph rendering shader
        this._renderMaterial = new ShaderMaterial({
            glslVersion: GLSL3,
            uniforms: {
                tDiffuse: {value: null},
                uSamplingTexture: {value: this._samplingTarget.texture},
                uAtlas: {value: this._atlasTexture},
                uCellSize: {value: new Vector2(this.cellSize, this.cellSize)},
                uResolution: {value: new Vector2(1, 1)},
                uAtlasGrid: {value: this._atlasGrid},
                uSplitPosition: {value: this.splitPosition}
            },
            vertexShader: asciiVertexShader,
            fragmentShader: asciiRenderShader
        });

        this._fsQuad = new FullScreenQuad(null);
    }

    /**
     * Parse alphabet JSON, apply componentWiseGlobalNormalization,
     * pack into Vector4 + Vector2 arrays for Three.js uniform upload.
     */
    _prepareCharacterVectors(alphabetData) {
        const chars = alphabetData.characters;
        const characters = chars.map(c => c.char);

        // Extract raw vectors (immutable copy)
        const vectors = chars.map(c => [...c.vector]);

        // componentWiseGlobalNormalization: normalize each dimension independently
        for (let dim = 0; dim < 6; dim++) {
            let maxVal = 0;
            for (const v of vectors) {
                maxVal = Math.max(maxVal, v[dim]);
            }
            if (maxVal > 0) {
                for (const v of vectors) {
                    v[dim] /= maxVal;
                }
            }
        }

        // Pack into Vector4 (dims 0-3) and Vector2 (dims 4-5) for Three.js uniform arrays
        // Must use Three.js math objects (not plain objects) -- flatten() calls .toArray()
        const charVecA = vectors.map(v => new Vector4(v[0], v[1], v[2], v[3]));
        const charVecB = vectors.map(v => new Vector2(v[4], v[5]));

        return {charVecA, charVecB, characters};
    }

    /**
     * Generate a font atlas canvas texture at runtime.
     * 10 columns x 8 rows grid for 80 characters.
     */
    _generateFontAtlas(characters, cellSize) {
        const cols = 10;
        const rows = 8;
        // Generate at higher resolution for quality (2x the cell size, min 24px)
        const glyphW = Math.max(cellSize * 2, 24);
        const glyphH = Math.round(glyphW * 1.333); // Match default.json aspect ratio
        const canvas = document.createElement("canvas");
        canvas.width = cols * glyphW;
        canvas.height = rows * glyphH;

        const ctx = canvas.getContext("2d");
        ctx.fillStyle = "black";
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = "white";
        ctx.font = `${glyphH}px ${this.fontFamily}`;
        ctx.textBaseline = "top";
        ctx.textAlign = "center";

        for (let i = 0; i < characters.length; i++) {
            const col = i % cols;
            const row = Math.floor(i / cols);
            ctx.fillText(characters[i], col * glyphW + glyphW / 2, row * glyphH);
        }

        const texture = new CanvasTexture(canvas);
        texture.flipY = false; // Keep canvas top-down layout -- shader handles UV mapping
        texture.minFilter = LinearFilter;
        texture.magFilter = LinearFilter;
        texture.generateMipmaps = false;
        return texture;
    }

    render(renderer, writeBuffer, readBuffer /*, deltaTime */) {
        if (!this.enabled) return;

        // Step 1: Sample + match at grid resolution
        // Note: textureLod uses mip level 0 (point sampling) since readBuffer has no mipmaps.
        // Area averaging happens naturally at the low grid resolution.
        this._samplingMaterial.uniforms.tDiffuse.value = readBuffer.texture;
        this._samplingMaterial.uniforms.uCrunchExponent.value = this.crunchExponent;
        this._fsQuad.material = this._samplingMaterial;
        renderer.setRenderTarget(this._samplingTarget);
        renderer.clear();
        this._fsQuad.render(renderer);

        // Step 2: Render glyphs at full resolution
        this._renderMaterial.uniforms.tDiffuse.value = readBuffer.texture;
        this._renderMaterial.uniforms.uSplitPosition.value = this.splitPosition;
        this._fsQuad.material = this._renderMaterial;

        if (this.renderToScreen) {
            renderer.setRenderTarget(null);
        } else {
            renderer.setRenderTarget(writeBuffer);
            if (this.clear) renderer.clear();
        }
        this._fsQuad.render(renderer);
    }

    setSize(width, height) {
        const cols = Math.ceil(width / this.cellSize);
        const rows = Math.ceil(height / this.cellSize);
        this._samplingTarget.setSize(cols, rows);

        // Update uniforms
        const cellVec = new Vector2(this.cellSize, this.cellSize);
        const sceneRes = new Vector2(width, height);
        this._samplingMaterial.uniforms.uCellSize.value.copy(cellVec);
        this._samplingMaterial.uniforms.uSceneResolution.value.copy(sceneRes);
        this._renderMaterial.uniforms.uCellSize.value.copy(cellVec);
        this._renderMaterial.uniforms.uResolution.value.copy(sceneRes);
    }

    dispose() {
        this._samplingTarget.dispose();
        this._samplingMaterial.dispose();
        this._renderMaterial.dispose();
        this._fsQuad.dispose();
        if (this._atlasTexture) {
            this._atlasTexture.dispose();
        }
    }

    /**
     * Set up dat.gui controls for this pass.
     */
    setupGUI(gui) {
        const folder = gui.addFolder("ASCII Effect");
        folder.add(this, "enabled").name("Enable");
        folder.add(this, "cellSize", 6, 24, 1).name("Cell Size").onChange(val => {
            this.cellSize = val;
            // Regenerate atlas at new cell size
            if (this._atlasTexture) this._atlasTexture.dispose();
            this._atlasTexture = this._generateFontAtlas(this._characters, val);
            this._renderMaterial.uniforms.uAtlas.value = this._atlasTexture;
            // Trigger resize to recalculate grid
            const res = this._renderMaterial.uniforms.uResolution.value;
            this.setSize(res.x, res.y);
        });
        folder.add(this, "crunchExponent", 0.5, 3.0, 0.1).name("Contrast");
        folder.add(this, "splitPosition", 0.0, 1.0, 0.01).name("Split View");
        folder.open();
        return folder;
    }
}

