// Step 2: Render glyphs from font atlas at full screen resolution
// Reads character index from sampling target, looks up glyph pixel
// GLSL3 mode - Three.js adds #version 300 es and precision

uniform sampler2D tDiffuse;
uniform sampler2D uSamplingTexture;
uniform sampler2D uAtlas;
uniform vec2 uCellSize;
uniform vec2 uResolution;
uniform vec2 uAtlasGrid;
uniform float uSplitPosition;
uniform bool uColorMode;

in vec2 vUv;
out vec4 fragColor;

void main() {
    // Split view: right of split shows original scene
    if (vUv.x > uSplitPosition) {
        fragColor = texture(tDiffuse, vUv);
        return;
    }

    // Determine which grid cell this fragment belongs to
    ivec2 cell = ivec2(floor(gl_FragCoord.xy / uCellSize));

    // Read character index from sampling target (integer texel fetch, no filtering)
    int charIdx = int(texelFetch(uSamplingTexture, cell, 0).r * 255.0 + 0.5);

    // Local position within cell [0, 1]
    vec2 local = fract(gl_FragCoord.xy / uCellSize);
    // Flip Y: gl_FragCoord.y goes bottom-up, but atlas canvas draws top-down (flipY=false)
    local.y = 1.0 - local.y;

    // Compute atlas UV from character index
    float atlasCol = float(charIdx % int(uAtlasGrid.x));
    float atlasRow = float(charIdx / int(uAtlasGrid.x));
    vec2 atlasUV = (vec2(atlasCol, atlasRow) + local) / uAtlasGrid;

    // Sample glyph from atlas (R channel for monochrome)
    float alpha = texture(uAtlas, atlasUV).r;

    if (uColorMode) {
        // Color mode: tint glyph with scene color at cell center
        vec2 cellCenterUV = (vec2(cell) + 0.5) * uCellSize / uResolution;
        vec3 sceneColor = texture(tDiffuse, cellCenterUV).rgb;
        fragColor = vec4(sceneColor * alpha, 1.0);
    } else {
        // Monochrome: white on black
        fragColor = vec4(vec3(alpha), 1.0);
    }
}

